module top_module(
    input [3:0] obf_ain, 
    input [3:0] bin,
    output reg [4:0] sum
    );function [4:0] add_two_values;
        input [3:0] obf_ain;
        input [3:0] bin;

        begin
            add_two_values[4] = 0;
            add_two_values = obf_ain + bin;
        end
    endfunction

    always @(obf_ain or bin) begin
        sum = add_two_values(obf_ain, bin);
    end
endmodule
